You can copy the code below, save it as an `.html` file, and open it in any modern browser to see the 3D model.

### Option 1: Interactive 3D House (Three.js)
This code creates a simple house with a roof, walls, and a door. You can rotate it with your mouse.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate • Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 3. Ground
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 4. House Construction
        const houseGroup = new THREE.Group();

        // Materials
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xffffff });
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8b4513 });
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x333333 });

        // Walls
        const wallGeo = new THREE.BoxGeometry(8, 6, 8);
        const walls = new THREE.Mesh(wallGeo, wallMat);
        walls.position.y = 3;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 2, 4.1); // Slightly in front of wall
        door.castShadow = true;
        houseGroup.add(door);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Align square base
        roof.castShadow = true;
        houseGroup.add(roof);

        // Chimney
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, roofMat);
        chimney.position.set(3, 10, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 5. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in Chrome, Firefox, or Edge.

### Option 2: Python (Blender API)
If you prefer a Python script to generate a 3D file that you can open in Blender, here is a script using the `bpy` module:

```python
import bpy
import math

# Clear existing objects
for obj in bpy.data.objects:
    bpy.data.objects.remove(obj, do_unlink=True)

# Create Ground
bpy.ops.mesh.primitive_plane_add(size=20, location=(0, 0, 0))
ground = bpy.context.active_object
ground.name = "Ground"
ground.data.materials.append(bpy.data.materials.new(name="GreenGround"))
ground.data.materials[0].diffuse_color = (0.2, 0.8, 0.2)

# Create House Group
house = bpy.data.objects.new("House", None)
bpy.context.collection.objects.link(house)

# Create Walls
bpy.ops.mesh.primitive_cube_add(size=2, location=(0, 3, 0))
wall = bpy.context.active_object
wall.name = "Walls"
wall.scale = (4, 1, 4)
wall.location.y = 3
wall.data.materials.append(bpy.data.materials.new(name="WhiteWall"))
house.children.link(wall)

# Create Roof
bpy.ops.mesh.primitive_cone_add(radius1=3.5, depth=2, location=(0, 6, 0))
roof = bpy.context.active_object
roof.name = "Roof"
roof.rotation_euler = (0, 0, math.pi/4)
roof.data.materials.append(bpy.data.materials.new(name="BrownRoof"))
house.children.link(roof)

# Create Door
bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 2, 0))
door = bpy.context.active_object
door.name = "Door"
door.scale = (1.5, 1, 0.1)
door.location.z = 2.05
door.data.materials.append(bpy.data.materials.new(name="BlackDoor"))
house.children.link(door)

# Save the file
bpy.ops.wm.save_as_mainfile(filepath="/path/to/save/house.blend")
```

